mapper.update:
UPDATE collection_folder
name = #{name}, description = #{description}, article_count = #{articleCount}, sort_order = #{sortOrder}, default_folder = #{defaultFolder}, status = #{status}, deleted = #{deleted}, deleted_time = #{deletedTime}, update_time = #{updateTime}
WHERE id = #{id}

UPDATE collection_folder cf INNER JOIN (
SELECT #{item.id} AS id, #{item.sortOrder} AS sort_order
) temp ON cf.id = temp.id SET cf.sort_order = temp.sort_order, cf.update_time = NOW() WHERE cf.user_id = #{userId} AND cf.deleted = 0
